	@Test
	void optimizeShouldPreferValuesAndLeafVarsForCycle5ValuesDistinctMailboxOrdered() throws Exception {
		TestQueryAccess queryAccess = new TestQueryAccess();
		LmdbLftjOptimizer optimizer = new LmdbLftjOptimizer(
				new LmdbLftjTripleSource(new EmptyTripleSource(), queryAccess));

		TupleExpr tupleExpr = parsedQueryRoot(
				FoafCliqueQueryCatalog.QueryScenario.CYCLE5_VALUES_DISTINCT_MAILBOX_ORDERED.query());

		optimizer.optimize(tupleExpr, (Dataset) null, EmptyBindingSet.getInstance());

		LmdbLftjTupleExpr lftj = findNode(tupleExpr, LmdbLftjTupleExpr.class);
		assertInstanceOf(BindingSetAssignment.class, findNode(tupleExpr, BindingSetAssignment.class));
		assertInstanceOf(Distinct.class, findNode(tupleExpr, Distinct.class));
		assertInstanceOf(Order.class, findNode(tupleExpr, Order.class));
		Filter residualFilter = assertInstanceOf(Filter.class, findNode(tupleExpr, Filter.class));
		assertFilterDoesNotContainInequalities(residualFilter);
		assertEquals(List.of(
				new LmdbLftjPlan.OutputBinding("a", "a"),
				new LmdbLftjPlan.OutputBinding("aLabel", "aLabel"),
				new LmdbLftjPlan.OutputBinding("homepage", "homepage"),
				new LmdbLftjPlan.OutputBinding("mbox", "mbox")), lftj.plan().outputBindings());
		assertEquals(completeInequalities(5), lftj.plan().inequalityConstraints());

		List<String> variableOrder = lftj.plan().variableOrder();
		assertEquals(List.of("city", "a"), variableOrder.subList(0, 2));
		assertLeafVarsPrecedeCycleTail(variableOrder, List.of("mbox", "aLabel", "homepage"),
				List.of("b", "c", "d", "e"));
	}

	private TupleExpr cycle(String a, String b, String c) {
		StatementPattern pattern1 = statementPattern(a, b);
		StatementPattern pattern2 = statementPattern(b, c);
		StatementPattern pattern3 = statementPattern(c, a);
		return new Join(new Join(pattern1, pattern2), pattern3);
	}

	private StatementPattern statementPattern(String subjectName, String objectName) {
		return new StatementPattern(new Var(subjectName), new Var("pred", FOAF.KNOWS), new Var(objectName));
	}

	private TupleExpr distinctPredicateCycle(String a, String b, String c) {
		StatementPattern pattern1 = new StatementPattern(new Var(a), new Var("p1", VF.createIRI("urn:p1")), new Var(b));
		StatementPattern pattern2 = new StatementPattern(new Var(b), new Var("p2", VF.createIRI("urn:p2")), new Var(c));
		StatementPattern pattern3 = new StatementPattern(new Var(c), new Var("p3", VF.createIRI("urn:p3")), new Var(a));
		return new Join(new Join(pattern1, pattern2), pattern3);
	}

	private TupleExpr reorderedDistinctPredicateCycle(String a, String b, String c) {
		StatementPattern pattern1 = new StatementPattern(new Var(a), new Var("p1", VF.createIRI("urn:p1")), new Var(b));
		StatementPattern pattern2 = new StatementPattern(new Var(b), new Var("p2", VF.createIRI("urn:p2")), new Var(c));
		StatementPattern pattern3 = new StatementPattern(new Var(c), new Var("p3", VF.createIRI("urn:p3")), new Var(a));
		return new Join(new Join(pattern2, pattern3), pattern1);
	}

	private TupleExpr aliasedCycle() {
		Join join = new Join(new Join(statementPattern("a", "b"), statementPattern("b", "c")),
				statementPattern("c", "a"));
		Filter filter = new Filter(join, new And(
				new Compare(new Var("a"), new Var("b"), Compare.CompareOp.NE),
				new And(
						new Compare(new Var("a"), new Var("c"), Compare.CompareOp.NE),
						new Compare(new Var("b"), new Var("c"), Compare.CompareOp.NE))));
		Extension extension = new Extension(filter);
		extension.addElement(new ExtensionElem(new Var("a"), "x"));
		extension.addElement(new ExtensionElem(new Var("b"), "y"));
		extension.addElement(new ExtensionElem(new Var("c"), "z"));
		return new Projection(extension, new ProjectionElemList(
				new ProjectionElem("x"),
				new ProjectionElem("y"),
				new ProjectionElem("z")));
	}

	private String aliasProjectionQuery() {
		return "PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n"
				+ "SELECT (?a AS ?x) (?b AS ?y) (?c AS ?z) WHERE {\n"
				+ "  ?a foaf:knows ?b .\n"
				+ "  ?b foaf:knows ?c .\n"
				+ "  ?c foaf:knows ?a .\n"
				+ "  FILTER (?a != ?b && ?a != ?c && ?b != ?c)\n"
				+ "}\n";
	}

	private String aliasProjectionWithResidualFilterQuery() {
		return "PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n"
				+ "SELECT (?a AS ?x) (?b AS ?y) (?c AS ?z) WHERE {\n"
				+ "  ?a foaf:knows ?b .\n"
				+ "  ?b foaf:knows ?c .\n"
				+ "  ?c foaf:knows ?a .\n"
				+ "  FILTER (?a != ?b && ?a != ?c && ?b != ?c && STRSTARTS(STR(?a), \"urn:person:1\"))\n"
				+ "}\n";
	}

	private String reorderedDuplicateAliasProjectionQuery() {
		return "PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n"
				+ "SELECT (?c AS ?z) (?a AS ?x) (?a AS ?x2) WHERE {\n"
				+ "  ?a foaf:knows ?b .\n"
				+ "  ?b foaf:knows ?c .\n"
				+ "  ?c foaf:knows ?a .\n"
				+ "  FILTER (?a != ?b && ?a != ?c && ?b != ?c)\n"
				+ "}\n";
	}

	private String duplicateReversedInequalityQuery() {
		return "PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n"
				+ "SELECT (?a AS ?x) (?b AS ?y) (?c AS ?z) WHERE {\n"
				+ "  ?a foaf:knows ?b .\n"
				+ "  ?b foaf:knows ?c .\n"
				+ "  ?c foaf:knows ?a .\n"
				+ "  FILTER (?b != ?a && ?a != ?b && ?c != ?a && ?b != ?c)\n"
				+ "}\n";
	}

	private String unsupportedOrFilterQuery() {
		return "PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n"
				+ "SELECT (?a AS ?x) (?b AS ?y) (?c AS ?z) WHERE {\n"
				+ "  ?a foaf:knows ?b .\n"
				+ "  ?b foaf:knows ?c .\n"
				+ "  ?c foaf:knows ?a .\n"
				+ "  FILTER (?a != ?b || ?a != ?c)\n"
				+ "}\n";
	}

	private String computedExtensionQuery() {
		return "PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n"
				+ "SELECT (STR(?a) AS ?x) ?b ?c WHERE {\n"
				+ "  ?a foaf:knows ?b .\n"
				+ "  ?b foaf:knows ?c .\n"
				+ "  ?c foaf:knows ?a .\n"
				+ "  FILTER (?a != ?b && ?a != ?c && ?b != ?c)\n"
				+ "}\n";
	}

	private String chainedAliasProjectionQuery() {
		return "PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n"
				+ "SELECT ?y ?b ?c WHERE {\n"
				+ "  ?a foaf:knows ?b .\n"
				+ "  ?b foaf:knows ?c .\n"
				+ "  ?c foaf:knows ?a .\n"
				+ "  FILTER (?a != ?b && ?a != ?c && ?b != ?c)\n"
				+ "  BIND(?a AS ?x)\n"
				+ "  BIND(?x AS ?y)\n"
				+ "}\n";
	}

	private String repeatedVariableQuery() {
		return "PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n"
				+ "SELECT * WHERE {\n"
				+ "  ?a foaf:knows ?a .\n"
				+ "  ?a foaf:knows ?b .\n"
				+ "  ?b foaf:knows ?a .\n"
				+ "}\n";
	}

	private TupleExpr parsedQueryRoot(String query) throws Exception {
		ParsedTupleQuery parsed = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null);
		TupleExpr tupleExpr = parsed.getTupleExpr().clone();
		if (!(tupleExpr instanceof QueryRoot)) {
			tupleExpr = new QueryRoot(tupleExpr);
		}
		return tupleExpr;
	}

	private LmdbLftjTupleExpr lftjNode(TupleExpr tupleExpr) {
		return assertInstanceOf(LmdbLftjTupleExpr.class, assertInstanceOf(QueryRoot.class, tupleExpr).getArg());
	}

	private <T extends QueryModelNode> T findNode(TupleExpr tupleExpr, Class<T> type) {
		QueryModelNode[] result = new QueryModelNode[1];
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) {
				if (result[0] == null && type.isInstance(node)) {
					result[0] = node;
				}
				super.meetNode(node);
			}
		});
		return type.cast(result[0]);
	}

	private List<LmdbLftjPlan.InequalityConstraint> completeInequalities(int size) {
		List<LmdbLftjPlan.InequalityConstraint> inequalities = new java.util.ArrayList<>();
		for (int i = 0; i < size; i++) {
			for (int j = i + 1; j < size; j++) {
				inequalities.add(new LmdbLftjPlan.InequalityConstraint(variableName(i), variableName(j)));
			}
		}
		return inequalities;
	}

	private String variableName(int index) {
		return String.valueOf((char) ('a' + index));
	}

	private void assertLeafVarsPrecedeCycleTail(List<String> variableOrder, List<String> leafVars,
			List<String> cycleTail) {
		Map<String, Integer> positions = new LinkedHashMap<>();
		for (int i = 0; i < variableOrder.size(); i++) {
			positions.put(variableOrder.get(i), i);
		}
		for (String leafVar : leafVars) {
			for (String cycleVar : cycleTail) {
				assertTrue(positions.get(leafVar) < positions.get(cycleVar),
						() -> "expected " + leafVar + " before " + cycleVar + " in " + variableOrder);
			}
		}
	}

	private void assertFilterDoesNotContainInequalities(Filter filter) {
		List<Compare> inequalities = new java.util.ArrayList<>();
		filter.getCondition().visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Compare node) {
				if (node.getOperator() == Compare.CompareOp.NE) {
					inequalities.add(node);
				}
				super.meet(node);
			}
		});
		assertEquals(List.of(), inequalities,
				"supported != conjuncts should be removed from the residual outer filter");
	}

	private static final class EmptyTripleSource implements TripleSource {

		@Override
		public org.eclipse.rdf4j.common.iteration.CloseableIteration<? extends Statement> getStatements(Resource subj,
				IRI pred, Value obj, Resource... contexts) throws QueryEvaluationException {
			return new EmptyIteration<>();
		}

		@Override
		public org.eclipse.rdf4j.model.ValueFactory getValueFactory() {
			return SimpleValueFactory.getInstance();
		}
	}

	private static final class TestQueryAccess implements LmdbQueryAccess {

		private final Map<String, LmdbLftjPlanner.PlanningResult> cachedPlans = new HashMap<>();
		private int cachedPlanHits;
		private int cachedPlanPuts;

		@Override
		public TripleStore tripleStore() {
			return null;
		}

		@Override
		public TxnManager.Txn acquireReadTxn() {
			throw new UnsupportedOperationException();
		}

		@Override
		public void releaseReadTxn(TxnManager.Txn txn) {
			throw new UnsupportedOperationException();
		}

		@Override
		public long resolveId(Value value) {
			throw new UnsupportedOperationException();
		}

		@Override
		public Value resolveValue(long id) {
			throw new UnsupportedOperationException();
		}

		@Override
		public boolean includeInferred() {
			return false;
		}

		@Override
		public Set<String> configuredIndexes() {
			return Set.of("spoc", "sopc", "psoc", "posc", "ospc", "opsc");
		}

		@Override
		public RecordIterator openScan(TxnManager.Txn txn, String indexName, long subj, long pred, long obj,
				long context, boolean explicit) {
			throw new UnsupportedOperationException();
		}

		@Override
		public LmdbTrieKeyCursor openTrieCursor(TxnManager.Txn txn, String indexName, boolean explicit) {
			throw new UnsupportedOperationException();
		}

		@Override
		public LmdbLftjPlanner.PlanningResult cachedPlanningResult(String cacheKey) {
			LmdbLftjPlanner.PlanningResult result = cachedPlans.get(cacheKey);
			if (result != null) {
				cachedPlanHits++;
			}
			return result;
		}

		@Override
		public void cachePlanningResult(String cacheKey, LmdbLftjPlanner.PlanningResult result) {
			cachedPlanPuts++;
			cachedPlans.put(cacheKey, result);
		}
	}
